# DiskStation Monitor — Database graceful startup patch
# Run: Set-ExecutionPolicy Bypass -Scope Process -Force; .\PATCH2.ps1

$RepoPath = "C:\Users\LionelMosley\Documents\HTML\Synology - DiskStation Monitor"
Set-Location $RepoPath
Write-Host "Applying database graceful-startup patch..." -ForegroundColor Cyan

# backend/src/db/client.ts
$b64 = ""
$bytes = [System.Convert]::FromBase64String($b64)
$fullPath = Join-Path $RepoPath "backend/src/db/client.ts"
[System.IO.File]::WriteAllBytes($fullPath, $bytes)
Write-Host "  wrote backend/src/db/client.ts" -ForegroundColor Green

# backend/src/services/redis.ts
$b64 = ""
$bytes = [System.Convert]::FromBase64String($b64)
$fullPath = Join-Path $RepoPath "backend/src/services/redis.ts"
[System.IO.File]::WriteAllBytes($fullPath, $bytes)
Write-Host "  wrote backend/src/services/redis.ts" -ForegroundColor Green

git add backend/src/db/client.ts backend/src/services/redis.ts
git commit -m "fix: graceful startup without DATABASE_URL/REDIS_URL — add plugins in Railway to resolve"
git push origin main

if ($LASTEXITCODE -eq 0) {
    Write-Host "`n✅ Patch pushed!" -ForegroundColor Green
    Write-Host "   Now add PostgreSQL + Redis in Railway dashboard:" -ForegroundColor Cyan
    Write-Host "   https://railway.app → tender-peace → + Add → Database → PostgreSQL" -ForegroundColor Yellow
    Write-Host "   https://railway.app → tender-peace → + Add → Database → Redis" -ForegroundColor Yellow
} else {
    Write-Host "`n❌ Push failed." -ForegroundColor Red
}